const user = {
  profile: {
    address: {
      city: 'Lahore'
    }
  }
};

// Without optional chaining — crashes if any part is undefined
// const city = user.profile.address.city; // works here but fragile

// With optional chaining — safe
const city = user?.profile?.address?.city;
console.log(city); // 'Lahore'

const zip = user?.profile?.address?.zip;
console.log(zip); // undefined (no error)

// With nullish coalescing for a default
const displayZip = user?.profile?.address?.zip ?? 'N/A';
console.log(displayZip); // 'N/A'

// Optional method call
const length = user?.getFullName?.();
console.log(length); // undefined (method doesn't exist, no crash)

// Optional computed property
const key = 'city';
console.log(user?.profile?.address?.[key]); // 'Lahore'
